// Get all rows from Google Sheets
const clients = $items("Get Client Data");

// Default professional fallback summary
let summary = "Global markets are experiencing moderate fluctuations. Maintaining a diversified portfolio and aligning investments with your risk profile is recommended.";

//  real API summary
if ($json && $json.feed && $json.feed.length > 0) {
  summary = $json.feed[0].summary;
}

// Filter ONLY new clients 
const newClients = clients.filter(client => {
  const status = client.json.Status;

  return (
    status === undefined ||
    status === null ||
    status.toString().trim() === ""
  );
});

// Stop workflow if no new client
if (newClients.length === 0) {
  return [];
}

// Take ONLY first new client
const client = newClients[0];

// Return formatted data
return [
  {
    json: {
      ...client.json,
      marketSummary: summary
    }
  }
];

